        private static List<VocabularyItem> FillMissingRelationTranslations(List<VocabularyItem> items)
        {
            var relationTranslations = GetRelationTranslationsByWord();
            var seedTranslations = BuildSeedTranslationsByWord(items);

            foreach (var item in items)
            {
                item.SynonymsJson = FillRelationJson(item.SynonymsJson, relationTranslations, seedTranslations);
                item.IdiomsJson = FillRelationJson(item.IdiomsJson, relationTranslations, seedTranslations);
            }

            return items;
        }

        private static string FillRelationJson(
            string? json,
            Dictionary<string, string> relationTranslations,
            Dictionary<string, string> seedTranslations)
        {
            var list = JsonSerializer.Deserialize<List<VocabularyRelationSeed>>(json ?? "[]") ?? new List<VocabularyRelationSeed>();

            foreach (var relation in list)
            {
                if (!string.IsNullOrWhiteSpace(relation.Translation))
                {
                    continue;
                }

                var key = (relation.Word ?? string.Empty).Trim();

                if (string.IsNullOrWhiteSpace(key))
                {
                    continue;
                }

                if (relationTranslations.TryGetValue(key, out var fromMap))
                {
                    relation.Translation = fromMap;
                    continue;
                }

                if (seedTranslations.TryGetValue(key, out var fromSeeds))
                {
                    relation.Translation = fromSeeds;
                }
            }

            return JsonSerializer.Serialize(list);
        }

        private static Dictionary<string, string> BuildSeedTranslationsByWord(List<VocabularyItem> items)
        {
            var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

            foreach (var item in items)
            {
                var translations = SplitSeedTranslations(item.Translation);

                if (translations.Count == 0)
                {
                    continue;
                }

                if (!map.ContainsKey(item.Word))
                {
                    map[item.Word] = translations[0];
                }
            }

            return map;
        }

        private static List<string> SplitSeedTranslations(string value)
        {
            value = (value ?? string.Empty).Trim();

            if (string.IsNullOrWhiteSpace(value))
            {
                return new List<string>();
            }

            value = value
                .Replace(" або ", "|", StringComparison.OrdinalIgnoreCase)
                .Replace(" or ", "|", StringComparison.OrdinalIgnoreCase);

            return value
                .Split(new[] { '/', ',', ';', '|', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)
                .Select(x => (x ?? string.Empty).Trim())
                .Where(x => !string.IsNullOrWhiteSpace(x))
                .ToList();
        }

